import * as React from "react";

const API_URL = import.meta.env.VITE_SUBSCRIBE_URL;
const MACRO_CALCULATOR_URL = import.meta.env.VITE_MACRO_CALCULATOR_URL;
const MACRO_CALCULATOR_GROUP_ID = import.meta.env
  .VITE_MACRO_CALCULATOR_GROUP_ID;

export const App: React.FC = () => {
  return (
    <>
      {/* DIALOG */}
      <dialog
        id="dialog"
        popover="auto"
        className="bg-background border border-border/50 rounded-xl w-full max-w-lg fixed top-full lg:top-1/2 left-1/2 -translate-x-1/2 -translate-y-full lg:-translate-y-1/2 backdrop:bg-background/90 animate-in duration-1000 fade-in-0 slide-in-from-bottom-4 z-50"
      >
        <div className="space-y-4 p-6">
          <header className="leading-relaxed">
            <h2 className="font-header tracking-tight text-3xl lg:text-4xl uppercase text-foreground">
              Calculadora de Macros <span className="text-accent">Pro</span>
            </h2>
            <p className="text-muted">
              Has sido redirigido automáticamente. Descubre exactamente cuántas
              calorías y proteína necesitas según tu objetivo.
            </p>
          </header>
          <a
            href={MACRO_CALCULATOR_URL}
            target="_blank"
            rel="noopener noreferrer"
            className="text-accent hover:text-accent-hover underline underline-offset-4 text-sm transition-colors"
          >
            {MACRO_CALCULATOR_URL}
          </a>
        </div>
        <div className="border-t border-border/30 flex justify-end p-6 pt-4">
          <button
            popoverTarget="dialog"
            popoverTargetAction="hide"
            className="bg-accent rounded-md py-2 px-4 text-sm font-semibold text-background text-center cursor-pointer hover:opacity-90 transition-opacity"
          >
            Cerrar
          </button>
        </div>
      </dialog>

      {/* NAV */}
      <nav className="border-b border-border/50 px-6 flex justify-center items-center fixed top-0 w-full h-20 bg-background/50 backdrop-blur animate-in duration-1000 fade-in-0 slide-in-from-bottom-4 z-10">
        <header className="font-header text-2xl tracking-wide uppercase">
          Xatruch <span className="text-accent">Fitness</span>
        </header>
      </nav>

      {/* MAIN GRID */}
      <main className="max-w-xl lg:max-w-6xl mx-auto px-6 py-9 grid grid-cols-1 lg:grid-cols-5 gap-12 items-center mt-20 animate-in duration-1000 fade-in-0 slide-in-from-bottom-4">
        {/* LEFT COLUMN */}
        <section className="flex flex-col gap-y-6 lg:col-span-3">
          {/* Pill */}
          <div className="inline-flex items-center gap-2 border border-border rounded-full px-3.5 py-1.5 w-fit bg-background-2/30">
            <span className="size-1.5 rounded-full bg-accent shrink-0 inline-block" />
            <span className="tracking-[0.2em] text-xs font-semibold text-muted uppercase">
              Herramienta Gratuita
            </span>
          </div>

          {/* Headline */}
          <h1 className="font-header text-5xl lg:text-7xl tracking-tight uppercase leading-none">
            La única calculadora que{" "}
            <span className="text-accent">necesitas</span> para transformar tu
            cuerpo
          </h1>

          {/* Subtext */}
          <p className="leading-relaxed text-muted">
            Descubre exactamente cuántas calorías comer y cuánta proteína
            necesitas — sin confusión, sin suposiciones, sin perder tiempo.
          </p>

          {/* Features */}
          <div className="flex flex-col gap-3 mt-1">
            <p>
              <span className="text-accent mr-2">✓</span>
              <span className="text-muted">
                Calcula tus calorías exactas según tu objetivo: perder grasa o
                ganar músculo
              </span>
            </p>
            <p>
              <span className="text-accent mr-2">✓</span>
              <span className="text-muted">
                Descubre tu meta de proteína diaria para proteger o construir
                músculo
              </span>
            </p>
            <p>
              <span className="text-accent mr-2">✓</span>
              <span className="text-muted">
                Sin fórmulas complicadas — solo introduces tus datos y listo
              </span>
            </p>
          </div>
        </section>

        {/* RIGHT COLUMN */}
        <section className="flex flex-col gap-y-6 lg:col-span-2">
          <img
            alt="Calculator 3D icon"
            draggable="false"
            loading="lazy"
            decoding="async"
            className="mx-auto w-1/2"
            src="data:image/webp;base64,"
          />
          <div className="flex flex-col gap-y-6 relative">
            {/* Badge */}
            <div className="mx-auto inline-flex items-center gap-2 border border-accent rounded-full px-3.5 py-1.5 w-fit bg-accent absolute inset-x-0">
              <span className="tracking-[0.2em] text-xs text-background uppercase font-bold">
                Gratis · Acceso Inmediato
              </span>
            </div>

            {/* Email Card */}
            <div className="bg-background-2/30 border border-border/30 rounded-xl p-6 pt-9 mt-3 space-y-4">
              <header className="leading-relaxed">
                <h2 className="font-header tracking-tight text-3xl lg:text-4xl uppercase">
                  Todo lo que quiero es tu email
                </h2>
                <p className="text-muted">
                  Accede gratis a la Calculadora de Macros Pro ahora mismo
                </p>
              </header>

              {/* Inputs */}
              <form
                data-loading="false"
                data-error="false"
                className="group space-y-4"
                onSubmit={async (e) => {
                  e.preventDefault();
                  const form = e.currentTarget;
                  if (form.dataset.loading === "true") return;

                  form.dataset.loading = "true";
                  form.dataset.error = "false";

                  try {
                    const data = new FormData(form);
                    const res = await fetch(API_URL, {
                      method: "POST",
                      headers: { "Content-Type": "application/json" },
                      body: JSON.stringify({
                        name: data.get("name"),
                        email: data.get("email"),
                        objetivo: data.get("objetivo"),
                        groupId: MACRO_CALCULATOR_GROUP_ID,
                      }),
                    });

                    if (!res.ok) throw new Error();

                    form.reset();
                    document
                      .querySelector("select")
                      ?.parentElement?.setAttribute("data-has-value", "false");
                    window.open(MACRO_CALCULATOR_URL, "_blank");
                    document.getElementById("dialog")?.showPopover();
                  } catch {
                    form.dataset.error = "true";
                  } finally {
                    form.dataset.loading = "false";
                  }
                }}
                onReset={() => {
                  document
                    .querySelector("select")
                    ?.parentElement?.setAttribute("data-has-value", "false");
                  window.open(MACRO_CALCULATOR_URL, "_blank");
                }}
              >
                <input
                  required
                  type="text"
                  name="name"
                  placeholder="Hector Sosa"
                  className="bg-border/10 border border-border/30 rounded-md px-3 py-3 text-sm placeholder:text-muted text-foreground w-full outline-none focus:border-accent transition-colors user-invalid:focus:border-pink-600 user-invalid:border-pink-600 user-invalid:placeholder:text-pink-600"
                />
                <input
                  required
                  type="email"
                  name="email"
                  placeholder="hector.sosa@gmail.com"
                  className="bg-border/10 [-internal-autofill-selected]:bg-border/10 border border-border/30 rounded-md px-3 py-3 text-sm placeholder:text-muted text-foreground w-full outline-none focus:border-accent transition-colors user-invalid:focus:border-pink-600 user-invalid:border-pink-600 user-invalid:placeholder:text-pink-600"
                />
                <div className="w-full relative group" data-has-value="false">
                  <select
                    required
                    name="objetivo"
                    defaultValue=""
                    className="bg-border/10 border border-border/30 rounded-md px-3 py-3 text-sm w-full outline-none focus:border-accent transition-colors   appearance-none cursor-pointer text-muted group-data-[has-value=true]:text-foreground user-invalid:focus:border-pink-600 user-invalid:border-pink-600 user-invalid:text-pink-600"
                    onChange={(e) => {
                      e.target.parentElement?.setAttribute(
                        "data-has-value",
                        String(e.target.value !== ""),
                      );
                    }}
                  >
                    <option value="" disabled hidden>
                      Tu objetivo
                    </option>
                    <option value="Perder Grasa">Perder Grasa</option>
                    <option value="Ganar Masa Muscular">
                      Ganar Masa Muscular
                    </option>
                  </select>
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="currentColor"
                    className="size-6 absolute right-3 top-1/2 -translate-y-1/2 text-muted pointer-events-none group-data-[has-value=true]:hidden"
                  >
                    <path d="m6 9 6 6 6-6" />
                  </svg>
                </div>

                {/* Idle button */}
                <button
                  type="submit"
                  className="group-data-[loading=true]:hidden bg-accent rounded-md py-3 text-sm font-semibold text-background text-center w-full hover:opacity-90 transition-opacity cursor-pointer inline-flex items-center justify-center gap-1.5"
                >
                  Quiero mis macros ahora
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="currentColor"
                    className="size-4 stroke-2"
                  >
                    <path d="M5 12h14" />
                    <path d="m12 5 7 7-7 7" />
                  </svg>
                </button>

                {/* Loading button */}
                <button
                  disabled
                  type="button"
                  className="hidden group-data-[loading=true]:inline-flex bg-accent/60 rounded-md py-3 text-sm font-semibold text-background/80 text-center w-full items-center justify-center gap-2 cursor-not-allowed"
                >
                  <svg
                    className="animate-spin size-4 stroke-2"
                    xmlns="http://www.w3.org/2000/svg"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="currentColor"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  >
                    <path d="M21 12a9 9 0 1 1-6.219-8.56" />
                  </svg>
                  Enviando...
                </button>

                {/* Error message */}
                <p
                  className="hidden group-data-[error=true]:block text-pink-600 text-sm text-center"
                  role="alert"
                >
                  Algo salió mal. Intenta de nuevo.
                </p>
              </form>

              {/* No spam */}
              <div className="text-xs text-muted text-center">
                <span className="mr-2">🔒</span>
                <span>Sin spam, sólo contenido que te ayuda a progresar.</span>
              </div>
            </div>
          </div>
        </section>
      </main>
    </>
  );
};
